+    impl Future for PendingOnceFuture {
+        type Output = usize;
+
+        fn poll(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Self::Output> {
+            self.poll_counter.fetch_add(1, Ordering::SeqCst);
+            if self.polled_once {
+                Poll::Ready(self.value)
+            } else {
+                self.polled_once = true;
+                Poll::Pending
+            }
+        }
+    }
